import{_ as a,c as i,o as t,ah as r}from"./chunks/framework.BaqsfJuc.js";const m=JSON.parse('{"title":"Duoxiang Zhao","description":"","frontmatter":{"layout":"doc","prev":false,"next":false},"headers":[],"relativePath":"about-me/index.md","filePath":"about-me/index.md"}'),n={name:"about-me/index.md"};function s(l,e,o,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="duoxiang-zhao" tabindex="-1">Duoxiang Zhao <a class="header-anchor" href="#duoxiang-zhao" aria-label="Permalink to “Duoxiang Zhao”">​</a></h1><p>Student</p><p>Major in Computer Science at Sichuan University - Pittsburgh Institute (SCUPI)</p><h2 id="education" tabindex="-1">Education <a class="header-anchor" href="#education" aria-label="Permalink to “Education”">​</a></h2><ul><li><strong>Sichuan University</strong>, Chengdu, China (September 2023 - June 2027, estimated) <ul><li>Major in Computer Science at the Pittsburgh Institute (SCUPI)</li></ul></li></ul><h2 id="achievements" tabindex="-1">Achievements <a class="header-anchor" href="#achievements" aria-label="Permalink to “Achievements”">​</a></h2><ul><li>2025-09 - Provincial Second Prize in_National Undergraduate Mathematical Contest in Modeling</li><li>2025-09 - The Second Prize Scholarship, Sichuan University (2024-2025 Academic Year)</li><li>2025-09 - Outstanding Student Leader, Sichuan University (2024-2025 Academic Year)</li><li>2024-09 - The Third Prize Scholarship, Sichuan University (2023-2024 Academic Year)</li><li>2022-09 - Second Prize in National High School Mathematics League (Preliminary)</li></ul><h2 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to “Skills”">​</a></h2><h3 id="natural-languages" tabindex="-1">Natural Languages <a class="header-anchor" href="#natural-languages" aria-label="Permalink to “Natural Languages”">​</a></h3><ul><li>English (CET 6)</li><li>Chinese (Native)</li></ul><h3 id="programming-languages" tabindex="-1">Programming Languages <a class="header-anchor" href="#programming-languages" aria-label="Permalink to “Programming Languages”">​</a></h3><ul><li>C and C++ - Algorithm and systems programming</li><li>Java - Object-oriented development</li><li>Python - Data science and deep learning</li><li>JavaScript - Frontend development</li></ul><h3 id="other-skills" tabindex="-1">Other Skills <a class="header-anchor" href="#other-skills" aria-label="Permalink to “Other Skills”">​</a></h3><ul><li>CUDA</li><li>Ubuntu</li><li>Docker</li><li>Markdown</li><li>LaTeX</li></ul><h2 id="publications" tabindex="-1">Publications <a class="header-anchor" href="#publications" aria-label="Permalink to “Publications”">​</a></h2><ul><li>Xing Wei, <strong>Duoxiang Zhao</strong>, et al. &quot;GPG-HT: Generalized Policy Gradient with History-Aware Decision Transformer for Probabilistic Path Planning,&quot; under review, 2025.</li><li><strong>Duoxiang Zhao</strong>, et al. &quot;Conceptor-Augmented Regularization for RNN and LSTM Networks,&quot; in <em>Proc. 2025 IEEE 2nd International Conference on Deep Learning and Computer Vision (DLCV)</em>, 2025. doi: <a href="https://doi.org/10.1109/DLCV65218.2025.11088507" target="_blank" rel="noreferrer">10.1109/DLCV65218.2025.11088507</a><details class="details custom-block"><summary>Abstract</summary><p>Recurrent Neural Network (RNN) and its variants, such as Long Short-Term Memory (LSTM), have achieved remarkable success in sequential data processing tasks. The representations learned by their hidden layers often require further regularization to enhance model performance and robustness. In this paper, we propose a novel Conceptor-based regularization mechanism for improving the hidden state representations of RNN and LSTM networks. Unlike previous works that primarily treat Conceptors as classifiers, we introduce a dynamic Conceptor layer integrated within the hidden states of RNNs and LSTM networks, termed Conceptor-Augmented RNN (CA-RNN) and Conceptor-Augmented LSTM (CA-LSTM). We evaluate the proposed method on the task of classifying speakers using Japanese vowel recordings, comparing standard RNN and LSTM models with those augmented by our Conceptor-based regularization. Our results demonstrate that incorporating the proposed dynamic Conceptor mechanism significantly improves classification performance and noise resistance, highlighting its effectiveness as a hidden-state regularizer for sequential models.</p></details></li></ul><h2 id="research-experiences" tabindex="-1">Research Experiences <a class="header-anchor" href="#research-experiences" aria-label="Permalink to “Research Experiences”">​</a></h2><h3 id="research-student-at-scupi-cs-laboratory" tabindex="-1">Research Student at SCUPI CS Laboratory <a class="header-anchor" href="#research-student-at-scupi-cs-laboratory" aria-label="Permalink to “Research Student at SCUPI CS Laboratory”">​</a></h3><details class="details custom-block"><summary>Details</summary><ul><li>Sichuan University - Pittsburgh Institute (May 2025 - present)</li><li>Advisors: Prof. Guangwu Qian, Prof. Yuqi Ouyang</li><li>Focus on deep learning applications, feedback networks, and video anomaly detection</li><li>Maintained lab servers and deployment pipelines; gained familiarity with distributed infrastructure</li></ul></details><h3 id="honor-undergraduate-research" tabindex="-1">Honor Undergraduate Research <a class="header-anchor" href="#honor-undergraduate-research" aria-label="Permalink to “Honor Undergraduate Research”">​</a></h3><details class="details custom-block"><summary>Details</summary><ul><li>Sichuan University - Pittsburgh Institute (April 2024 - April 2025)</li><li>Learned the full research workflow, from literature review to experimentation</li><li>Practiced software tooling for academic research and inspected state-of-the-art methods</li></ul></details><h3 id="modeling-optimization-at-west-china-hospital" tabindex="-1">Modeling Optimization at West China Hospital <a class="header-anchor" href="#modeling-optimization-at-west-china-hospital" aria-label="Permalink to “Modeling Optimization at West China Hospital”">​</a></h3><details class="details custom-block"><summary>Details</summary><ul><li>Sichuan University - West China Hospital (Sept. 2024 - Oct. 2024)</li><li>Applied convolutional neural networks for visual classification of pressure ulcer stages</li><li>Mitigated overfitting via data augmentation and algorithmic refinements</li><li>Improved model implementations for robustness</li></ul></details><h2 id="teaching-experiences" tabindex="-1">Teaching Experiences <a class="header-anchor" href="#teaching-experiences" aria-label="Permalink to “Teaching Experiences”">​</a></h2><h3 id="teaching-assistant-for-infsci-0510-data-analysis" tabindex="-1">Teaching Assistant for INFSCI 0510: Data Analysis <a class="header-anchor" href="#teaching-assistant-for-infsci-0510-data-analysis" aria-label="Permalink to “Teaching Assistant for INFSCI 0510: Data Analysis”">​</a></h3><details class="details custom-block"><summary>Details</summary><ul><li>Sichuan University - Pittsburgh Institute (March 2026 - June 2026)</li><li>Supported an introductory machine learning course: logistic regression, SVM, decision trees, KNN, Naive Bayes, PCA, K-Means, DBSCAN, GMM, EM, ensemble methods, and evaluation</li><li>Held lab hours and graded assignments and exams</li></ul></details>',26)])])}const g=a(n,[["render",s]]);export{m as __pageData,g as default};
